import sys
from math import isqrt

def solve():
    input_data = sys.stdin.buffer.read().split()
    MOD = 10**9 + 7
    n = int(input_data[0])
    a = [int(x) for x in input_data[1:n+1]]

    A = max(a)
    # Compute phi
    phi = list(range(A+1))
    for i in range(2, A+1):
        if phi[i] == i:  # prime
            for j in range(i, A+1, i):
                phi[j] -= phi[j] // i

    # Precompute divisors of each a[i]
    divs = [[] for _ in range(n)]
    for idx in range(n):
        x = a[idx]
        for d in range(1, isqrt(x)+1):
            if x % d == 0:
                divs[idx].append(d)
                if d != x // d:
                    divs[idx].append(x // d)

    phi_n = [0] * (n+1)
    for i in range(1, n+1):
        phi_n[i] = i
    for i in range(2, n+1):
        if phi_n[i] == i:
            for j in range(i, n+1, i):
                phi_n[j] -= phi_n[j] // i

    ans = 0
    f = [0] * (A+1)

    for d2 in range(1, n+1):
        # collect indices that are multiples of d2
        indices = range(d2-1, n, d2)  # 0-indexed: d2, 2*d2, ... -> indices d2-1, 2*d2-1,...
        touched = []
        for idx in indices:
            for d1 in divs[idx]:
                if f[d1] == 0:
                    touched.append(d1)
                f[d1] += 1

        s = 0
        for d1 in touched:
            s += phi[d1] * f[d1] * f[d1]
            f[d1] = 0

        ans = (ans + phi_n[d2] * s) % MOD

    print(ans % MOD)

solve()
